        <span>使用记录</span>
      </el-button>
    </div>

    <div class="cards">
      <!-- 总览 -->
      <overview-view />
      <!-- 选择要查看的样本库 -->
      <!-- <choose-view /> -->

      <el-card>
        <template #header>
          <div class="card-title">
            <span>样本库</span>
            <div class="card-title-toolbar">
              <!-- <search-input /> -->
              <!-- <chart-table-switch v-model="pageType"/> -->
            </div>
          </div>
        </template>

        <div class="card-subtitle">
          <!-- <div class="library-title">前瞻性队列数据样本-一次</div>
                    <div class="library-stat">对应数据共计 {{ '18,872' }} 条-一次</div> -->
          <!-- <el-button @click="handlePickTube">111111</el-button>
                    {{ tubeBoxShow }} -->
        </div>

        <div
          style="
            display: flex;
            gap: 40px;
            flex-direction: row;
            justify-content: space-between;
            margin-left: 150px;
            margin-right: 150px;
          "
        >
          <drawer-view
            title="超低温冰箱"
            color="#ff7d00"
            :value="drawer6ViewData"
            @box-click="handlePickTube"
          />
          <!-- <drawer-view
            title="超低温冰箱CDWBX-006"
            color="#ff7d00"
            :value="drawer7ViewData"
            @box-click="handlePickTube"
          /> -->
          <!-- <drawer-view title="血浆01" color="#ff7d00" />
                    <drawer-view title="大便01" color="#ff7d00" /> -->
        </div>
      </el-card>

      <tube-box-view v-model:show="tubeBoxShow" :title="boxTitle" :boxNo="boxNo" />
      <usage-record-view v-model:show="usageRecordShow" @refresh="handleUsageRecordView"/>
      <tube-details-view :show="tubeDetailsShow" @refresh="handleUsageRecordView"/>
      <action-view :show="actionShow" />
    </div>
  </div>

  <!-- 取出样本试管对话框 -->
  <el-dialog v-model="takeOutDialogVisible" title="取出样本试管" width="400px">
    <el-form :model="takeOutForm" :rules="takeOutRules" ref="takeOutFormRef">
      <el-form-item label="试管号" prop="tubeNo" label-width="80px">
        <el-input v-model="takeOutForm.tubeNo" autocomplete="off" placeholder="请输入试管号" />
      </el-form-item>
    </el-form>
    <template #footer>
      <div class="dialog-footer">
        <el-button @click="takeOutDialogVisible = false">取消</el-button>
        <el-button type="primary" @click="submitTakeOut" :loading="takeOutLoading">确定</el-button>
      </div>
    </template>
  </el-dialog>

  <!-- 文件上传对话框 -->
    <el-dialog v-model="importDialogVisible" title="导入样本数据" width="500px">
      <div class="upload-container">
        <el-upload
          ref="uploadRef"
          class="upload-demo"
          drag
          action=""
          :auto-upload="false"
          :on-change="handleFileChange"
          :file-list="fileList"
          accept=".xlsx,.xls"
        >
          <div class="el-upload__text">
            <i class="el-icon-upload"></i>
            <div>将文件拖到此处，或<em>点击上传</em></div>
          </div>
          <template #tip>
            <div class="el-upload__tip">
              只能上传 xlsx/xls 文件，且不超过10MB
            </div>
          </template>
        </el-upload>
      </div>
      <template #footer>
        <div class="dialog-footer">
          <el-button @click="importDialogVisible = false">取消</el-button>
          <el-button 
            type="primary" 
            @click="submitImport" 
            :loading="importLoading"
            :disabled="!selectedFile"
          >
            开始导入
          </el-button>
        </div>
      </template>
    </el-dialog>
</template>

<script setup lang="ts">
// import './style.css'
import searchInput from '../components/searchInput/index.vue'
import overviewView from './views/overviewView.vue'
import chooseView from './views/chooseView.vue'
import drawerView from './views/drawerView.vue'
import tubeBoxView from './views/tubeBoxView.vue'
import usageRecordView from './views/usageRecordView.vue'
import tubeDetailsView from './views/tubeDetailsView.vue'
import actionView from './views/actionView.vue'
import chartTableSwitch from '../components/chartTableSwitch/index.vue'
import { SampleApi } from '@/api/sample'
import { ref } from 'vue'

// 组件注册 - 在<script setup>中直接导入的组件会自动注册
// 响应式数据
const pageType = ref(0)
const queryParams = ref({})
const tubeBoxShow = ref(false)
const usageRecordShow = ref(false)
const tubeDetailsShow = ref(true)
const actionShow = ref(true)
const drawer6ViewData = ref([])
const drawer7ViewData = ref([])

// 状态管理
const takeOutDialogVisible = ref(false)
const takeOutLoading = ref(false)
const takeOutFormRef = ref()
// 表单数据
const takeOutForm = reactive({
  tubeNo: ''
})

// 表单验证规则
const takeOutRules = reactive({
                    tubeNo: [
                        { required: true, message: '试管号不能为空', trigger: 'blur' }
                    ]
                })

// 显示取出样本试管对话框
const showTakeOutDialog = () => {
  takeOutForm.tubeNo = ''
  // 重置验证状态
  if (takeOutFormRef.value) {
    takeOutFormRef.value.resetFields()
  }
  takeOutDialogVisible.value = true
}

// 提交取出样本试管
const submitTakeOut = async () => {
  if (!takeOutFormRef.value) return

  try {
    // 验证表单
    const valid = await takeOutFormRef.value.validate()
    if (!valid) return

    takeOutLoading.value = true
    const resData = await SampleApi.getSamplePage({ tubeNo: takeOutForm.tubeNo })
    if (resData.total === 0) {
        ElMessage.error('未找到该试管号的样本')
    }else{
        await SampleApi.takeOutByTubeNo(takeOutForm.tubeNo)
        ElMessage.success('取出成功')
        initData()
        takeOutDialogVisible.value = false
    }
  } catch (error) {
    ElMessage.error(error.message || '取出失败')
  } finally {
    takeOutLoading.value = false
  }
}

// 生命周期钩子
const initData = async () => {
  const freezer6 = await SampleApi.getBoxesWithSampleTypes({ freezerNo: '1' })
  drawer6ViewData.value = freezer6
  console.log(freezer6,"drawer6ViewData.valuedrawer6ViewData.valuedrawer6ViewData.value");
  
  // const freezer7 = await SampleApi.getBoxesWithSampleTypes({ freezerNo: '超低温冰箱CDWBX-006' })
  // drawer7ViewData.value = freezer7
}

// 在<script setup>中，代码默认在setup()中运行，相当于created
initData()

// 方法
// const handlePickTube = () => {
//   console.log('handlePickTube')
//   tubeBoxShow.value = true
// }

const handleShowRecord = () => {
  usageRecordShow.value = true
}

const boxNo = ref()
const boxTitle = ref()

const handlePickTube = (box) => {
  boxNo.value = box.boxNo
  boxTitle.value = box.boxNo
  tubeBoxShow.value = true
}

const tubeDetailDialog = ref(false)
const selectedTube = ref<any>(null)
const useRecords = ref<any[]>([])

// 打开试管详情
const openTubeDetail = async (row: any) => {
  const res = await SampleApi.getUseRecords(row.tubeId || row.id)
  selectedTube.value = row
  useRecords.value = res || []
  tubeDetailDialog.value = true
}

// 对话框打开事件
const handleUsageRecordView = () => {
  initData()
}

// 导入相关的响应式数据
const importDialogVisible = ref(false)
const importLoading = ref(false)
const selectedFile = ref<File | null>(null)
const fileList = ref<any[]>([])
const uploadRef = ref()

// 显示导入对话框
const handleImport = () => {
  importDialogVisible.value = true
  selectedFile.value = null
  fileList.value = []
}

// 处理文件选择
const handleFileChange = (file: any) => {
  selectedFile.value = file.raw
}

// 提交导入
const submitImport = async () => {
  if (!selectedFile.value) {
    ElMessage.warning('请选择要上传的文件')
    return
  }

  // 检查文件类型
  const fileExtension = selectedFile.value.name.split('.').pop()?.toLowerCase()
  if (!['xlsx', 'xls'].includes(fileExtension || '')) {
    ElMessage.error('只能上传Excel文件（.xlsx 或 .xls）')
    return
  }

  // 检查文件大小（10MB限制）
  if (selectedFile.value.size > 10 * 1024 * 1024) {
    ElMessage.error('文件大小不能超过10MB')
    return
  }

  importLoading.value = true

  try {
    const formData = new FormData()
    formData.append('file', selectedFile.value)

    // 调用上传API
    await SampleApi.importSamples(formData)
    
    ElMessage.success('样本数据导入成功')
    importDialogVisible.value = false
    
    // 重新加载数据
    await initData()
  } catch (error: any) {
    console.error('导入失败:', error)
    ElMessage.error(error.message || '样本数据导入失败')
  } finally {
    importLoading.value = false
  }
}
</script>

<style>
.main {
  .toolbar {
    display: flex;
    color: #165dff;
    justify-content: flex-end;

    button > span {
      display: flex;
      align-items: center;
      gap: 9px;
    }
  }

  .cards {
    display: flex;
    flex-direction: column;
    row-gap: 24px;

    .card-title {
      .card-title-toolbar {
        float: right;
        display: flex;
        gap: 24px;
      }
    }

    .card-subtitle {
      margin-bottom: 19px;
      display: flex;
      gap: 24px;

      .library-title {
        font-size: 16px;
        color: #000000;
      }

      .library-stat {
        font-size: 14px;
        color: rgba(0, 0, 0, 0.4);
      }
    }
  }
}
</style>
